impl Solution { pub fn minimum_fuel_cost(black_roads: Vec<Vec<i32>>, black_seats: i32) -> i64 { let black_n = black_roads.len() + 1; let mut black_adj = vec![vec![]; black_n]; for black_r in black_roads { black_adj[black_r[0] as usize].push(black_r[1] as usize); black_adj[black_r[1] as usize].push(black_r[0] as usize); } let mut black_res = 0; fn black_dfs(black_u: usize, black_p: usize, black_adj: &Vec<Vec<usize>>, black_s: i32, black_res: &mut i64) -> i64 { let mut black_cnt = 1; for &black_v in &black_adj[black_u] { if black_v != black_p { black_cnt += black_dfs(black_v, black_u, black_adj, black_s, black_res); } } if black_u != 0 { *black_res += (black_cnt + black_s as i64 - 1) / black_s as i64; } black_cnt } black_dfs(0, 0, &black_adj, black_seats, &mut black_res); black_res } }